+                };
+
+                let first_seen = first_seen_opt
+                    .and_then(|s| chrono::DateTime::parse_from_rfc3339(&s).ok())
+                    .map_or_else(Utc::now, |dt| dt.with_timezone(&Utc));
+                let last_seen = last_seen_opt
